import React, { useEffect, useState } from "react";
import { Container, Card, Form, Button, Row, Col, Spinner } from "react-bootstrap";
import { toast } from "react-toastify";
import { useAuth } from "../context/AuthContext";
import api from "../services/api";

function Profile() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [medicalHistory, setMedicalHistory] = useState({
    diagnosis: "",
    conditions: "",
    allergies: "",
    notes: ""
  });

  useEffect(() => {
    fetchMedicalHistory();
  }, []);

  const fetchMedicalHistory = async () => {
    try {
      const res = await api.get("/api/profile/medical-history");
      // Ensure we always have the structure even if empty
      setMedicalHistory({
        diagnosis: res.data.diagnosis || "",
        conditions: res.data.conditions || "",
        allergies: res.data.allergies || "",
        notes: res.data.notes || ""
      });
    } catch (err) {
      console.error("Fetch medical history error:", err);
      toast.error("Failed to load medical history");
      // Set empty values on error
      setMedicalHistory({
        diagnosis: "",
        conditions: "",
        allergies: "",
        notes: ""
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);

    try {
      await api.put("/api/profile/medical-history", medicalHistory);
      toast.success("Medical history updated successfully");
    } catch (err) {
      console.error("Update medical history error:", err);
      toast.error(err.response?.data?.error || "Failed to update medical history");
    } finally {
      setSaving(false);
    }
  };

  const handleChange = (e) => {
    setMedicalHistory({
      ...medicalHistory,
      [e.target.name]: e.target.value
    });
  };

  if (loading) {
    return (
      <Container className="mt-4 text-center">
        <Spinner animation="border" variant="primary" />
        <p className="mt-2">Loading profile...</p>
      </Container>
    );
  }

  return (
    <Container className="mt-4">
      <h2 className="mb-4">
        <i className="bi bi-person-circle me-2"></i>
        Profile & Medical History
      </h2>

      <Row>
        <Col md={4}>
          <Card className="mb-4">
            <Card.Body className="text-center">
              <i className="bi bi-person-circle text-primary" style={{ fontSize: "5rem" }}></i>
              <h4 className="mt-3">{user?.name}</h4>
              <p className="text-muted">{user?.email}</p>
              <hr />
              <div className="text-start">
                <p className="mb-2">
                  <i className="bi bi-shield-lock me-2 text-success"></i>
                  <small>All data is encrypted</small>
                </p>
                <p className="mb-0">
                  <i className="bi bi-calendar me-2 text-info"></i>
                  <small>Member since {new Date().getFullYear()}</small>
                </p>
              </div>
            </Card.Body>
          </Card>

          {/* Medical History Summary Card */}
          <Card className="mb-4 border-info">
            <Card.Header className="bg-info text-white">
              <h6 className="mb-0">
                <i className="bi bi-clipboard2-pulse me-2"></i>
                Medical History Summary
              </h6>
            </Card.Header>
            <Card.Body>
              <div className="mb-3">
                <small className="text-muted d-block mb-1">Diagnosis</small>
                <p className="mb-0">
                  {medicalHistory.diagnosis ? (
                    <small>{medicalHistory.diagnosis.substring(0, 100)}{medicalHistory.diagnosis.length > 100 ? "..." : ""}</small>
                  ) : (
                    <small className="text-muted fst-italic">Not provided</small>
                  )}
                </p>
              </div>

              <div className="mb-3">
                <small className="text-muted d-block mb-1">Conditions</small>
                <p className="mb-0">
                  {medicalHistory.conditions ? (
                    <small>{medicalHistory.conditions.substring(0, 100)}{medicalHistory.conditions.length > 100 ? "..." : ""}</small>
                  ) : (
                    <small className="text-muted fst-italic">Not provided</small>
                  )}
                </p>
              </div>

              <div className="mb-3">
                <small className="text-muted d-block mb-1">Allergies</small>
                <p className="mb-0">
                  {medicalHistory.allergies ? (
                    <small className="text-danger fw-bold">{medicalHistory.allergies}</small>
                  ) : (
                    <small className="text-muted fst-italic">None reported</small>
                  )}
                </p>
              </div>

              {medicalHistory.updated_at && (
                <div className="text-center mt-3 pt-3 border-top">
                  <small className="text-muted">
                    <i className="bi bi-clock-history me-1"></i>
                    Last updated: {new Date(medicalHistory.updated_at).toLocaleDateString()}
                  </small>
                </div>
              )}
            </Card.Body>
          </Card>
        </Col>

        <Col md={8}>
          <Card>
            <Card.Header>
              <h5 className="mb-0">
                <i className="bi bi-clipboard2-pulse me-2"></i>
                Medical History
              </h5>
            </Card.Header>
            <Card.Body>
              <div className="alert alert-info small">
                <i className="bi bi-info-circle me-2"></i>
                This information is encrypted and only visible to you. 
                It's for your personal records only.
              </div>

              <Form onSubmit={handleSubmit}>
                <Form.Group className="mb-3">
                  <Form.Label>Diagnosis</Form.Label>
                  <Form.Control
                    as="textarea"
                    rows={3}
                    name="diagnosis"
                    placeholder="Enter any diagnoses..."
                    value={medicalHistory.diagnosis}
                    onChange={handleChange}
                  />
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label>Medical Conditions</Form.Label>
                  <Form.Control
                    as="textarea"
                    rows={3}
                    name="conditions"
                    placeholder="List any ongoing medical conditions..."
                    value={medicalHistory.conditions}
                    onChange={handleChange}
                  />
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label>Allergies</Form.Label>
                  <Form.Control
                    as="textarea"
                    rows={2}
                    name="allergies"
                    placeholder="List any allergies..."
                    value={medicalHistory.allergies}
                    onChange={handleChange}
                  />
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label>Additional Notes</Form.Label>
                  <Form.Control
                    as="textarea"
                    rows={4}
                    name="notes"
                    placeholder="Any additional medical notes..."
                    value={medicalHistory.notes}
                    onChange={handleChange}
                  />
                </Form.Group>

                <Button 
                  variant="primary" 
                  type="submit" 
                  disabled={saving}
                  className="w-100"
                >
                  {saving ? (
                    <>
                      <span className="spinner-border spinner-border-sm me-2"></span>
                      Saving...
                    </>
                  ) : (
                    <>
                      <i className="bi bi-save me-2"></i>
                      Save Medical History
                    </>
                  )}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default Profile;
